:root{font-family:Inter,system-ui,Arial;background:#0b1220;color:#e7edf7}*{box-sizing:border-box}body{margin:0}.page{max-width:980px;margin:0 auto;padding:18px}h1,h2,h3{margin:12px 0}.status{background:#172235;border:1px solid #2b3a56;padding:10px;border-radius:10px;color:#cbd7ea}.upload{display:block;background:#166534;padding:18px;border-radius:14px;text-align:center;font-weight:800;margin:16px 0}.upload input{display:none}.project{display:flex;width:100%;justify-content:space-between;margin:8px 0;padding:16px;border-radius:12px;border:1px solid #2b3a56;background:#111a2b;color:white;text-align:left}.project span{color:#9fb0cc}header{display:flex;gap:10px;align-items:center;justify-content:space-between;position:sticky;top:0;background:#0b1220;padding:8px 0;z-index:2}small{display:block;color:#9fb0cc}.filters{display:grid;grid-template-columns:1fr 1fr auto 80px;gap:8px;margin:12px 0}.card{background:#101a2c;border:1px solid #2b3a56;border-radius:14px;padding:14px;margin:12px 0}.playnum{font-size:24px;font-weight:900}.meta{color:#cbd7ea;margin:8px 0}pre{white-space:pre-wrap;background:#0b1220;padding:10px;border-radius:10px;color:#b8c6dd;max-height:120px;overflow:auto}.grid{display:grid;grid-template-columns:repeat(2,1fr);gap:10px}.grid.small{grid-template-columns:repeat(4,1fr)}button,select,input{border:1px solid #33415f;background:#1b2b46;color:white;border-radius:10px;padding:13px;font-size:16px}button{font-weight:800}.sel{background:#2563eb!important}.result{font-size:22px;font-weight:900;margin-top:12px}.nav{display:grid;grid-template-columns:repeat(4,1fr);gap:8px;position:sticky;bottom:0;background:#0b1220;padding:10px 0}@media(max-width:650px){.filters{grid-template-columns:1fr 1fr}.grid.small{grid-template-columns:repeat(3,1fr)}header{font-size:13px}button,select,input{padding:12px 8px}}
